trace.message:
@{
          return new JObject(
            new JProperty("timestamp", DateTime.UtcNow.ToString("o")),
            new JProperty("requestId", context.RequestId),
            new JProperty("operationName", context.Operation?.Name),
            new JProperty("statusCode", context.Response?.StatusCode),
            new JProperty("reason", context.Response?.StatusReason),
            new JProperty("errorReason", context.LastError?.Reason),
            new JProperty("errorMessage", context.LastError?.Message),
            new JProperty("responseBody", context.Response?.Body?.As<string>(preserveContent: true))
          ).ToString();
        }
